export class ErrorMessageParser {
  /**
   * Barrel serial number patterns:
   * - Standard format: 24HF.08.1852, 24H06A.99.0002
   * - Alternative format: BARREL_001
   * - In sentences: "Barrel ${barrelSN}", "barrel ${barrel.serialNumber}"
   */
  private static readonly BARREL_SN_PATTERNS = [
    // Standard format like 24HF.08.1852, 24H06A.99.0002
    /\b\d{2}[A-Z]+\.\d{2,3}(?:\.\d{4})?\b/g,
    // Alternative format like BARREL_001, BARREL001
    /\bBARREL[_-]?\d{3,}\b/gi,
    // Within quotes or variable references
    /'([^']*\d{2}[A-Z]+\.\d{2,3}(?:\.\d{4})?[^']*)'/g,
    // After "Barrel " or "barrel "
    /(?:Barrel|barrel)\s+([A-Z0-9._-]+\d+[A-Z0-9._-]*)/gi,
    // Between single quotes that looks like a barrel SN
    /'([A-Z0-9._-]*\d{2}[A-Z]+\.\d{2,3}(?:\.\d{4})?[A-Z0-9._-]*)'/g,
  ];

  /**
   * Location string patterns:
   * - Storage locations: 01-WHK01-01-1-003-A-6, WH01-002
   * - Holding locations: RickHouseFloor5, TempHolding
   */
  private static readonly LOCATION_PATTERNS = [
    // Standard storage location format: 01-WHK01-01-1-003-A-6
    /\b\d{2}-WH[A-Z0-9]+-\d{2}-\d+-\d{3}-[A-Z]-\d+\b/g,
    // Simplified warehouse format: WH01-002, WHK01-001
    /\bWH[A-Z0-9]+-\d{3,}\b/gi,
    // Holding location names (letters/numbers, no dashes or fewer dashes)
    /\b[A-Z][a-zA-Z0-9]*(?:Floor|House|Hold|Area|Zone|Temp)[A-Z0-9]*\b/gi,
    // After "location " keyword
    /(?:location|Location)\s+([A-Z0-9-._]+)/gi,
    // Between quotes for locations
    /'([^']*(?:WH|Floor|Hold|Area|Zone|Temp)[^']*)'/gi,
    // Location with ID reference
    /location\s+with\s+ID\s+([A-Z0-9-._]+)/gi,
