/**
 * Check data consistency
 */
private async checkConsistency(auditLog: any): Promise<IntegrityCheckDetail> {
  const issues: string[] = [];
  let status: "pass" | "fail" | "warning" = "pass";
  let severity: "low" | "medium" | "high" | "critical" = "low";

  // Check operation result consistency
  if (
    auditLog.operationResult === EnumAuditOperationResult.success &&
    auditLog.errorMessage
  ) {
    issues.push("Successful operation has error message");
    status = "warning";
    severity = "medium";
  }

  if (
    auditLog.operationResult === EnumAuditOperationResult.failure &&
    !auditLog.errorMessage
  ) {
    issues.push("Failed operation lacks error message");
    status = "fail";
    severity = "high";
  }

  // Check state consistency for update operations
  if (auditLog.operationType === EnumAuditOperationType.Update) {
    if (!auditLog.beforeState && !auditLog.afterState) {
      issues.push("Update operation missing both before and after states");
      status = "fail";
      severity = "critical";
    } else if (!auditLog.beforeState) {
      issues.push("Update operation missing before state");
      status = "warning";
      severity = "medium";
    } else if (!auditLog.afterState) {
      issues.push("Update operation missing after state");
      status = "warning";
      severity = "medium";
    }
  }

  return {
    checkType: "consistency",
    auditLogId: auditLog.id,
    entityType: auditLog.entityType,
    operationType: auditLog.operationType,
    status,
    issues,
    severity,
    autoFixable: false, // Consistency issues generally require manual review
  };
}

