  constructor(private readonly prisma: PrismaService) {}

  /**
   * Get the default safety configuration
   */
  async getDefaultConfig(): Promise<SafetyConfig | null> {
    try {
      const config = await this.prisma.$queryRaw<SafetyConfig[]>`
        SELECT * FROM "InventoryProcessingSafetyConfig"
        WHERE "configName" = 'default' AND "enabled" = true
        LIMIT 1
      `;

      return config.length > 0 ? config[0] : null;
    } catch (error) {
      this.logger.error("Failed to get default safety config:", error);
      return null;
    }
  }

