function isValidRickValue(value: string): boolean {
  return [
    EnumStorageLocationRick.A,
    EnumStorageLocationRick.B,
    EnumStorageLocationRick.C,
    EnumStorageLocationRick.Hallway,
  ].includes(value as EnumStorageLocationRick);
}

function convertToRickEnum(value: string): EnumStorageLocationRick {
  if (isValidRickValue(value)) {
    return value as EnumStorageLocationRick;
  }
  // Default to Hallway if invalid
  const logger = new Logger("RickEnumHelper");
  logger.warn(`Invalid rick value: ${value}, defaulting to Hallway`);
  return EnumStorageLocationRick.Hallway;
}

