): Promise<string[] | undefined> {
  if (!whiskeyTypeCodes || whiskeyTypeCodes.length === 0) {
    return undefined;
  }

  const whiskeyTypes = await this.prisma.whiskeyType.findMany({
    where: {
      code: { in: whiskeyTypeCodes },
    },
    select: { id: true },
  });

  return whiskeyTypes.map((wt) => wt.id);
}

