function hasCustomerNameSort(obj: unknown): obj is { customerName: SortOrder } {
  return (
    typeof obj === "object" &&
    obj !== null &&
    "customerName" in obj &&
    (obj as Record<string, unknown>).customerName !== undefined
  );
}

