export class ManhourConfigurationService extends ManhourConfigurationServiceBase {
  constructor(protected readonly prisma: PrismaService) {
    super(prisma);
  }

  /**
   * Get aggregate barrels filled per day based on manhour configurations
   * All dates between effectiveDate and expirationDate apply for that date
   * If a record has no expirationDate and is active, it applies to all dates after its effectiveDate
   * Data can be grouped by day, week, or month
   */
  async getBarrelsFilledAggregate(
    queryParams: BarrelsFilledQueryDto,
  ): Promise<BarrelsFilledAggregateDto[]> {
    const { startDate, endDate, groupBy = GroupByType.DAY } = queryParams;
    const now = new Date();

    // Normalize the date range - ensure proper Date objects
    const requestedStartDate = startDate
      ? new Date(startDate)
      : new Date(now.getFullYear(), now.getMonth(), now.getDate() - 30);
    const requestedEndDate = endDate ? new Date(endDate) : now;

