/**
 * Resolves customer from a lot's furnishing customer or recipe data
 */
async resolveCustomerFromLot(
  lot: Lot & { recipe?: any },
): Promise<Customer | null> {
  try {
    // First, try furnishing customer
    if (lot.furnishingCustomerId) {
      const customer = await this.prisma.customer.findUnique({
        where: { id: lot.furnishingCustomerId },
      });
      if (customer) return customer;
    }

    // Second, try extracting from recipe data
    if (lot.recipe && lot.recipe.data) {
      const recipeData = lot.recipe.data as any;

      // Try customerId first (direct database ID reference)
      if (recipeData.customerId) {
        const customer = await this.prisma.customer.findUnique({
          where: { id: recipeData.customerId },
        });
        if (customer) return customer;
      }

      // Fall back to customerCode lookup
      const customerCode = recipeData.customerCode || recipeData.customer;
      if (customerCode) {
        const customer = await this.findCustomerByCode(customerCode);
        if (customer) return customer;
      }
    }

    return null;
  } catch (error) {
    this.logger.error(
      `Error resolving customer from lot ${lot.lotNumber}:`,
      error,
    );
    return null;
  }
}

