          );
          console.log(
            `[RELOCATION JOB DEBUG] Received value: ${JSON.stringify(value, null, 2)}`,
          );

          // Must be an object
          if (
            typeof value !== "object" ||
            value === null ||
            Array.isArray(value)
          ) {
            console.log(
              "[RELOCATION JOB DEBUG] VALIDATION FAILED: Value is not a valid object",
            );
            return false;
          }

          // jobLocationRange is OPTIONAL - if not provided, validation passes
