    const createdDocuments = await this.prisma.vectorDocument.findMany({
      where: { identityKey: { in: keys } },
      select: { id: true, identityKey: true },
    });

    return createdDocuments.map((doc) => doc.id);
  } catch (error) {
    console.error("Error storing documents in batch:", error);
    throw error;
  }
